def generate_reference_answer():
    import json
    from mcp_client import call_tool

    execution_log = []

    # Step 1: Get current price of AAPL
    execution_log.append("Step 1: Calling twelvedata_GetPrice for AAPL")
    raw_price_data = call_tool('twelvedata_GetPrice', {'params': {'symbol': 'AAPL'}})
    execution_log.append(f"[RAW] {str(raw_price_data)[:200]}")
    price_data = json.loads(raw_price_data) if isinstance(raw_price_data, str) else raw_price_data

    current_price_str = price_data.get('price')
    if current_price_str is None:
        return "Failed to retrieve current price for AAPL."
    try:
        current_price = float(current_price_str)
    except ValueError:
        return "Failed to parse current price for AAPL."

    execution_log.append(f"Current price for AAPL: ${current_price:.2f}")

    recommendation = ""
    relevant_data = {}
    triggered_branch = ""

    # Step 2: Conditional logic based on current price
    if current_price > 185.00:
        execution_log.append("Branch A triggered")
        triggered_branch = "A"
        # Action for Branch A: Get 52-week high/low
        execution_log.append("Calling twelvedata_GetQuote for AAPL to get 52-week range")
        raw_quote_data = call_tool('twelvedata_GetQuote', {'params': {'symbol': 'AAPL'}})
        execution_log.append(f"[RAW] {str(raw_quote_data)[:200]}")
        quote_data = json.loads(raw_quote_data) if isinstance(raw_quote_data, str) else raw_quote_data

        fifty_two_week = quote_data.get('fifty_two_week', {})
        high_52_week_str = fifty_two_week.get('high')
        low_52_week_str = fifty_two_week.get('low')

        if high_52_week_str and low_52_week_str:
            try:
                high_52_week = float(high_52_week_str)
                low_52_week = float(low_52_week_str)
                relevant_data = {
                    '52_week_high': high_52_week,
                    '52_week_low': low_52_week
                }
                recommendation = (
                    f"The current price of ${current_price:.2f} is {'' if current_price > low_52_week else 'at its '} "
                    f"relative to its 52-week high of ${high_52_week:.2f} and low of ${low_52_week:.2f}. "
                    f"Consider further analysis on its momentum."
                )
            except ValueError:
                recommendation = "Could not parse 52-week high/low data."
        else:
            recommendation = "Could not retrieve 52-week high/low data."

    elif 180.00 <= current_price <= 185.00:
        execution_log.append("Branch B triggered")
        triggered_branch = "B"
        # Action for Branch B: Get latest EOD price
        execution_log.append("Calling twelvedata_GetEod for AAPL to get latest EOD price")
        raw_eod_data = call_tool('twelvedata_GetEod', {'params': {'symbol': 'AAPL'}})
        execution_log.append(f"[RAW] {str(raw_eod_data)[:200]}")
        eod_data = json.loads(raw_eod_data) if isinstance(raw_eod_data, str) else eod_data

        eod_close_str = eod_data.get('close')
        if eod_close_str is not None:
            try:
                eod_close = float(eod_close_str)
                relevant_data = {'eod_close': eod_close}
                if current_price > eod_close:
                    recommendation = f"The current price of ${current_price:.2f} is above its latest EOD close of ${eod_close:.2f}. This indicates positive short-term sentiment."
                elif current_price < eod_close:
                    recommendation = f"The current price of ${current_price:.2f} is below its latest EOD close of ${eod_close:.2f}. This indicates negative short-term sentiment."
                else:
                    recommendation = f"The current price of ${current_price:.2f} is exactly at its latest EOD close. Watch for breakout."
            except ValueError:
                recommendation = "Could not parse latest EOD price."
        else:
            recommendation = "Could not retrieve latest EOD price."

    else: # current_price < 180.00
        execution_log.append("Branch C triggered")
        triggered_branch = "C"
        # Action for Branch C: Get SMA over 9 periods
        execution_log.append("Calling twelvedata_GetTimeSeriesSma for AAPL (9-period)")
        raw_sma_data = call_tool('twelvedata_GetTimeSeriesSma', {'params': {'symbol': 'AAPL', 'interval': '1day', 'time_period': 9, 'outputsize': 1}})
        execution_log.append(f"[RAW] {str(raw_sma_data)[:200]}")
        sma_data = json.loads(raw_sma_data) if isinstance(raw_sma_data, str) else sma_data

        sma_values = sma_data.get('values', [])
        if sma_values:
            latest_sma_str = sma_values[0].get('sma')
            if latest_sma_str is not None:
                try:
                    latest_sma = float(latest_sma_str)
                    relevant_data = {'latest_sma_9_period': latest_sma}
                    if current_price > latest_sma:
                        recommendation = f"The current price of ${current_price:.2f} is above its 9-period SMA of ${latest_sma:.2f}. This might indicate a short-term bullish trend."
                    else:
                        recommendation = f"The current price of ${current_price:.2f} is below its 9-period SMA of ${latest_sma:.2f}. This might indicate a short-term bearish trend."
                except ValueError:
                    recommendation = "Could not parse latest SMA value."
            else:
                recommendation = "Could not retrieve latest SMA value."
        else:
            recommendation = "Could not retrieve SMA data."

    final_answer = (
        f"Analysis for AAPL:\n" 
        f"Current Price: ${current_price:.2f}\n" 
        f"Triggered Analysis Branch: {triggered_branch}\n" 
        f"Relevant Data: {json.dumps(relevant_data, indent=2)}\n" 
        f"Recommendation: {recommendation}"
    )
    execution_log.append(f"Final result: {final_answer[:500]}")

    return "\n".join(execution_log)
